import { useState } from "react";
import axios from "axios";
import { Link } from "react-router-dom";
import AuthShell from "../../components/AuthShell";

function ForgotPassword() {
  const [email, setEmail] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [sentTo, setSentTo] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      await axios.post("http://localhost:8070/api/auth/forgot-password", { email });
      setSentTo(email);
      setEmail("");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to send reset email");
    } finally {
      setLoading(false);
    }
  };

  if (sentTo) {
    return (
      <AuthShell
        eyebrow="Recovery Email"
        title="Check your inbox"
        subtitle={`A reset link has been sent to ${sentTo}. The link expires in one hour.`}
        compact
        footer={
          <Link to="/login" style={{ color: "var(--primary)", fontWeight: 700 }}>
            Back to login
          </Link>
        }
      >
        <div
          style={{
            padding: "18px",
            borderRadius: "18px",
            background: "rgba(141, 187, 1, 0.1)",
            color: "var(--navy)",
            textAlign: "center",
            lineHeight: 1.7,
            fontWeight: 600,
          }}
        >
          Reset instructions are on the way. Check your spam folder if the message does not arrive soon.
        </div>
      </AuthShell>
    );
  }

  return (
    <AuthShell
      eyebrow="Password Recovery"
      title="Reset your password"
      subtitle="Enter the email connected to your account and we’ll send you a secure reset link."
      compact
      footer={
        <Link to="/login" style={{ color: "var(--primary)", fontWeight: 700 }}>
          Back to login
        </Link>
      }
    >
      {error ? (
        <div
          style={{
            marginBottom: "18px",
            padding: "14px 16px",
            borderRadius: "16px",
            border: "1px solid rgba(186, 94, 94, 0.18)",
            background: "rgba(255,255,255,0.92)",
            color: "var(--danger)",
            fontWeight: 600,
            fontSize: "14px",
          }}
        >
          {error}
        </div>
      ) : null}

      <form onSubmit={handleSubmit} style={{ display: "grid", gap: "18px" }}>
        <div>
          <label className="label">Email Address</label>
          <input
            className="input"
            type="email"
            placeholder="you@example.com"
            value={email}
            onChange={(e) => {
              setEmail(e.target.value);
              setError("");
            }}
            required
          />
        </div>

        <button type="submit" className="btn btnPrimary" disabled={loading} style={{ width: "100%" }}>
          {loading ? "Sending link..." : "Send Reset Link"}
        </button>
      </form>
    </AuthShell>
  );
}

export default ForgotPassword;
